define i1 @fold_select_fcmp_fpmath(i1 %cond, float %a) {
  %lhs = select i1 %cond, float %a, float 0.000000e+00, !fpmath !0
  %res = fcmp olt float %lhs, 0.000000e+00
  ret i1 %res
}

!0 = !{float 2.500000e+00}

define <2 x float> @select_fdiv(i1 %cond, <2 x float> %x, <2 x float> %y) {
  %op = fdiv <2 x float> %x, %y
  %ret = select nnan i1 %cond, <2 x float> %op, <2 x float> %x, !prof !0, !unpredictable !1
  ret <2 x float> %ret
}

